import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Namespace clore::net::protocol","description":"The clore::net::protocol namespace provides a centralized set of utilities for constructing, parsing, and validating messages exchanged over the network according to a defined protocol. Its primary responsibility is to handle the serialization and deserialization of JSON‑based requests and responses, with a strong emphasis on tool calls and completion responses. Notable declarations include functions for building request JSON (build_request_json), parsing raw response strings (parse_response), extracting textual content from responses (text_from_response, parse_response_text), manipulating tool call arguments and outputs (parse_tool_arguments, append_tool_outputs), and validating output formats such as JSON or markdown fragments (validate_json_output, validate_markdown_fragment_output). Architecturally, this namespace acts as the protocol abstraction layer, insulating the rest of the application from the low‑level details of message formatting and verification while ensuring that all communication adheres to the expected structure and semantics.","frontmatter":{"title":"Namespace clore::net::protocol","description":"The clore::net::protocol namespace provides a centralized set of utilities for constructing, parsing, and validating messages exchanged over the network according to a defined protocol. Its primary responsibility is to handle the serialization and deserialization of JSON‑based requests and responses, with a strong emphasis on tool calls and completion responses. Notable declarations include functions for building request JSON (build_request_json), parsing raw response strings (parse_response), extracting textual content from responses (text_from_response, parse_response_text), manipulating tool call arguments and outputs (parse_tool_arguments, append_tool_outputs), and validating output formats such as JSON or markdown fragments (validate_json_output, validate_markdown_fragment_output). Architecturally, this namespace acts as the protocol abstraction layer, insulating the rest of the application from the low‑level details of message formatting and verification while ensuring that all communication adheres to the expected structure and semantics.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/namespaces/clore/net/protocol/index.md","filePath":"en/clore/namespaces/clore/net/protocol/index.md"}'),n={name:"clore/namespaces/clore/net/protocol/index.md"};function s(i,e,l,c,p,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="namespace-clore-net-protocol" tabindex="-1">Namespace <code>clore::net::protocol</code> <a class="header-anchor" href="#namespace-clore-net-protocol" aria-label="Permalink to &quot;Namespace `clore::net::protocol`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>clore::net::protocol</code> namespace provides a centralized set of utilities for constructing, parsing, and validating messages exchanged over the network according to a defined protocol. Its primary responsibility is to handle the serialization and deserialization of JSON‑based requests and responses, with a strong emphasis on tool calls and completion responses. Notable declarations include functions for building request JSON (<code>build_request_json</code>), parsing raw response strings (<code>parse_response</code>), extracting textual content from responses (<code>text_from_response</code>, <code>parse_response_text</code>), manipulating tool call arguments and outputs (<code>parse_tool_arguments</code>, <code>append_tool_outputs</code>), and validating output formats such as JSON or markdown fragments (<code>validate_json_output</code>, <code>validate_markdown_fragment_output</code>). Architecturally, this namespace acts as the protocol abstraction layer, insulating the rest of the application from the low‑level details of message formatting and verification while ensuring that all communication adheres to the expected structure and semantics.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-protocol-append-tool-outputs" tabindex="-1"><code>clore::net::protocol::append_tool_outputs</code> <a class="header-anchor" href="#clore-net-protocol-append-tool-outputs" aria-label="Permalink to &quot;`clore::net::protocol::append_tool_outputs`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:469</code></p><p>Definition: <code>network/protocol.cppm:540</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>The function <code>clore::net::protocol::append_tool_outputs</code> appends tool outputs derived from a given <code>CompletionResponse</code> to the internal state identified by the first integer parameter. The third integer parameter may control the number of outputs appended or otherwise modify the operation. It returns an integer status code that indicates success or failure. Callers are responsible for providing a valid <code>CompletionResponse</code> containing the tool outputs and ensuring the identifier refers to an existing target.</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by callers to incorporate tool execution results back into the conversation history</li><li>Called after a tool call response is received and tool outputs have been collected</li></ul><h3 id="clore-net-protocol-build-request-json" tabindex="-1"><code>clore::net::protocol::build_request_json</code> <a class="header-anchor" href="#clore-net-protocol-build-request-json" aria-label="Permalink to &quot;`clore::net::protocol::build_request_json`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:457</code></p><p>Definition: <code>network/openai.cppm:465</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>The function <code>clore::net::protocol::build_request_json</code> constructs a JSON representation of a request as defined by the protocol. It accepts a single <code>const int &amp;</code> parameter and returns an <code>int</code> outcome. Callers are responsible for providing a valid integer that represents the necessary request context; the returned integer indicates the result of the construction operation.</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>serializing a completion request to JSON</li><li>preparing data for HTTP request</li><li>converting <code>CompletionRequest</code> to JSON string</li></ul><h3 id="clore-net-protocol-parse-response" tabindex="-1"><code>clore::net::protocol::parse_response</code> <a class="header-anchor" href="#clore-net-protocol-parse-response" aria-label="Permalink to &quot;`clore::net::protocol::parse_response`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:459</code></p><p>Definition: <code>network/openai.cppm:532</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::protocol::parse_response</code> accepts a raw response string as a <code>std::string_view</code> and returns an <code>int</code> that represents the parsed result. Its primary responsibility is to interpret the response data according to the protocol’s format and produce an integer value that callers can use for further processing, such as status codes or identifiers.</p><p>The caller is expected to provide a well-formed response string that conforms to the protocol conventions. The function’s contract does not define the behavior for malformed or unexpected input; callers should ensure the input is valid before invoking this function.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to parse a raw JSON response from an LLM API endpoint</li><li>Used in the protocol layer to convert HTTP response body to domain object</li><li>Typically invoked by higher-level functions that handle network responses</li></ul><h3 id="clore-net-protocol-parse-response-text" tabindex="-1"><code>clore::net::protocol::parse_response_text</code> <a class="header-anchor" href="#clore-net-protocol-parse-response-text" aria-label="Permalink to &quot;`clore::net::protocol::parse_response_text`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:475</code></p><p>Definition: <code>network/protocol.cppm:588</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>The template function <code>clore::net::protocol::parse_response_text</code> accepts a <code>const CompletionResponse &amp;</code> and returns an <code>int</code>. It is the caller’s entry point for extracting and parsing the textual component from a completion response. The <code>int</code> return value encodes the outcome of the parsing operation; its exact meaning depends on the template argument and should be interpreted according to the specific context in which the function is instantiated. Callers must supply a well-formed <code>CompletionResponse</code> and can rely on the function to handle the text‑parsing logic without needing to understand its internal implementation.</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to parse structured LLM responses into a specified type.</li><li>Combines text extraction and JSON parsing with error handling.</li></ul><h3 id="clore-net-protocol-parse-tool-arguments" tabindex="-1"><code>clore::net::protocol::parse_tool_arguments</code> <a class="header-anchor" href="#clore-net-protocol-parse-tool-arguments" aria-label="Permalink to &quot;`clore::net::protocol::parse_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:478</code></p><p>Definition: <code>network/protocol.cppm:603</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>The function <code>clore::net::protocol::parse_tool_arguments</code> is a public template that accepts a <code>const ToolCall &amp;</code> and returns an <code>int</code>. Its caller-facing responsibility is to parse the tool arguments contained in the given <code>ToolCall</code> object, producing an integer result that typically represents a status code (e.g., success or error) or a count of parsed arguments. The caller is expected to provide a valid <code>ToolCall</code> instance, and the return value indicates the outcome of the parsing operation as defined by the protocol conventions.</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to deserialize tool call arguments into a typed structure.</li><li>Typically called when processing a <code>ToolCall</code> to extract its arguments as a specific type.</li></ul><h3 id="clore-net-protocol-text-from-response" tabindex="-1"><code>clore::net::protocol::text_from_response</code> <a class="header-anchor" href="#clore-net-protocol-text-from-response" aria-label="Permalink to &quot;`clore::net::protocol::text_from_response`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:467</code></p><p>Definition: <code>network/protocol.cppm:524</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>The function <code>clore::net::protocol::text_from_response</code> extracts or processes the textual component of a <code>CompletionResponse</code>. Callers supply a <code>const CompletionResponse&amp;</code> and receive an <code>int</code> that indicates the result of the operation—typically a status code or the number of characters processed. The contract requires that the provided response is valid and that the caller interprets the returned integer according to the protocol’s conventions.</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>safely extract text content from <code>CompletionResponse</code></li><li>handle refusal, tool calls, or missing text errors</li><li>convert response to text or error</li></ul><h3 id="clore-net-protocol-validate-json-output" tabindex="-1"><code>clore::net::protocol::validate_json_output</code> <a class="header-anchor" href="#clore-net-protocol-validate-json-output" aria-label="Permalink to &quot;`clore::net::protocol::validate_json_output`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:463</code></p><p>Definition: <code>network/protocol.cppm:484</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>The caller-facing responsibility of <code>clore::net::protocol::validate_json_output</code> is to verify that the provided <code>std::string_view</code> represents a well-formed JSON output according to protocol expectations. The function returns an <code>int</code> status code that indicates whether the validation succeeded or failed, enabling callers to determine if the content is acceptable for further processing. The precise contract is that the input must be a syntactically valid JSON string that also meets any additional structural constraints defined by the protocol; a non-zero return value signals a validation failure.</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Validate JSON output before further processing</li><li>Check if LLM output is valid JSON</li></ul><h3 id="clore-net-protocol-validate-markdown-fragment-output" tabindex="-1"><code>clore::net::protocol::validate_markdown_fragment_output</code> <a class="header-anchor" href="#clore-net-protocol-validate-markdown-fragment-output" aria-label="Permalink to &quot;`clore::net::protocol::validate_markdown_fragment_output`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:465</code></p><p>Definition: <code>network/protocol.cppm:493</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>The function <code>clore::net::protocol::validate_markdown_fragment_output</code> accepts a <code>std::string_view</code> representing a markdown fragment output and returns an <code>int</code>. It verifies that the provided fragment conforms to the expected structural and semantic constraints of the protocol&#39;s markdown output format. A return value of zero typically indicates a valid fragment, while non-zero values signal specific validation failures, allowing callers to detect and handle malformed outputs. This function is part of the protocol&#39;s set of output validation utilities, used alongside similar validators like <code>clore::net::protocol::validate_json_output</code>.</p><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>validation step in LLM response processing</li><li>safeguard before markdown fragment interpretation</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net</a></li></ul>',63)])])}const m=o(n,[["render",s]]);export{h as __pageData,m as default};
